// const INPUT: &str = "";
const INPUT: &str = "mjqjpqmgbljsphdztnvjfqwrcgsmlb";

fn main() {
    let mut double = false;

    for window in INPUT.chars().collect::<Vec<char>>().windows(4) {
        println!("{:?}", window);

        double = false;

        for (i, char) in window.iter().enumerate() {
            for other_char in window.iter().skip(1) {
                println!("{}", other_char);
                if char == other_char {
                    double = true;
                    // println!("Double");
                }
            }
        }

        if !double {
            println!("Found start marker");
        }
    }
}
